@Composable
fun HeroSection(
    displayName: String,
    totalBalance: Long,
    income: Long,
    expenses: Long,
    allTimeBalance: Long = totalBalance,
    allTimeIncome: Long = income,
    allTimeExpenses: Long = expenses,
    greetingText: String = "Good morning,",
    greetingIcon: ImageVector = Icons.Filled.WbSunny
) {
    val cs = MaterialTheme.colorScheme
    val isDark = isSystemInDarkTheme()
    // hero colors: in dark mode use a near-black green-tinted background
    val heroPrimary = if (isDark) Color(0xFF07110D) else GreenDeep
    val heroMid = if (isDark) Color(0xFF0B1A14) else GreenMid
    val onPage = cs.onBackground
    val subtle = cs.onSurfaceVariant

    val initials = displayName
        .split(" ").filter { it.isNotBlank() }.take(2)
        .joinToString("") { it.first().uppercaseChar().toString() }
        .ifBlank { "?" }

    val monthLabel = SimpleDateFormat("MMMM yyyy", Locale.US).format(Date())

    val spendRatio = if (income > 0) (expenses.toFloat() / income).coerceIn(0f, 1f) else 0f
    val spendPct   = (spendRatio * 100).toInt()
    val remainPct  = (100 - spendPct).coerceAtLeast(0)
    val remaining  = (income - expenses).coerceAtLeast(0L)

    Column(
        modifier = Modifier
            .fillMaxWidth()
            .background(cs.background)
            .statusBarsPadding()
            .padding(horizontal = 20.dp)
            .padding(top = 12.dp, bottom = 24.dp)
    ) {
        // ── Greeting row ──────────────────────────────────────────────────────
        Row(
            modifier = Modifier.fillMaxWidth().padding(bottom = 28.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            Box(
                modifier = Modifier.size(40.dp).background(heroPrimary, CircleShape),
                contentAlignment = Alignment.Center
            ) {
                Text(initials, fontSize = 13.sp, fontWeight = FontWeight.Bold, color = White, fontFamily = InterFontFamily)
            }
            Column(modifier = Modifier.weight(1f).padding(horizontal = 12.dp)) {
                Row(verticalAlignment = Alignment.CenterVertically) {
                    Icon(greetingIcon, null, tint = subtle, modifier = Modifier.size(11.dp))
                    Spacer(Modifier.width(4.dp))
                    Text(greetingText, fontSize = 11.sp, color = subtle, fontFamily = InterFontFamily)
                }
                Text(
                    displayName.ifBlank { "User" },
                    fontSize = 15.sp, fontWeight = FontWeight.Bold, color = onPage,
                    maxLines = 1, overflow = TextOverflow.Ellipsis, fontFamily = InterFontFamily
                )
            }
            Box(
                modifier = Modifier
                    .size(38.dp)
                    .background(cs.surface, CircleShape)
                    .border(1.dp, cs.outline, CircleShape),
                contentAlignment = Alignment.Center
            ) {
                Icon(Icons.Outlined.NotificationsNone, null, modifier = Modifier.size(19.dp), tint = subtle)
            }
        }

        // ── Monthly Overview header ───────────────────────────────────────────
        Row(
            modifier = Modifier.fillMaxWidth().padding(bottom = 6.dp),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            Text("Monthly Overview", fontSize = 12.sp, fontWeight = FontWeight.Medium, color = subtle, letterSpacing = 0.3.sp, fontFamily = InterFontFamily)
            Text(monthLabel, fontSize = 11.sp, color = subtle, fontFamily = InterFontFamily)
        }

        // ── Main income amount ────────────────────────────────────────────────
        Text(
            String.format(Locale.US, "LKR %.2f", income / 100.0),
            fontSize = 34.sp, fontWeight = FontWeight.ExtraBold, color = onPage,
            letterSpacing = (-1.5).sp, modifier = Modifier.padding(bottom = 18.dp),
            fontFamily = InterFontFamily
        )

        // ── Spend / Remaining row ─────────────────────────────────────────────
        Row(modifier = Modifier.fillMaxWidth().padding(bottom = 12.dp), horizontalArrangement = Arrangement.SpaceBetween) {
            Column {
                Text("Spend", fontSize = 10.sp, fontWeight = FontWeight.Medium, color = subtle, letterSpacing = 0.5.sp, fontFamily = InterFontFamily)
                Text(
                    String.format(Locale.US, "LKR %.2f", expenses / 100.0),
                    fontSize = 15.sp, fontWeight = FontWeight.Bold, color = onPage,
                    letterSpacing = (-0.3).sp, fontFamily = InterFontFamily, modifier = Modifier.padding(top = 2.dp)
                )
            }
            Column(horizontalAlignment = Alignment.End) {
                Text("Remaining", fontSize = 10.sp, fontWeight = FontWeight.Medium, color = subtle, letterSpacing = 0.5.sp, fontFamily = InterFontFamily)
                Text(
                    String.format(Locale.US, "LKR %.2f", remaining / 100.0),
                    fontSize = 15.sp, fontWeight = FontWeight.Bold, color = GreenAccent,
                    letterSpacing = (-0.3).sp, fontFamily = InterFontFamily, modifier = Modifier.padding(top = 2.dp)
                )
            }
        }

         // ── Two circular progress indicators ──────────────────────────────────────
         Row(
             modifier = Modifier.fillMaxWidth().padding(bottom = 24.dp),
             horizontalArrangement = Arrangement.spacedBy(16.dp)
         ) {
             // Spend indicator
             CircularProgressIndicator(
                 percentage = spendPct,
                 label = "Spend",
                 modifier = Modifier.weight(1f)
             )

             // Remaining indicator
             CircularProgressIndicator(
                 percentage = remainPct,
                 label = "Remaining",
                 modifier = Modifier.weight(1f),
                 color = GreenAccent
             )
         }

        // ── Dark green balance card (hero) ───────────────────────────────────
        Box(
            modifier = Modifier
                .fillMaxWidth()
                .background(
                    brush = Brush.linearGradient(listOf(heroPrimary, heroMid, GreenBright)),
                    shape = RoundedCornerShape(20.dp)
                )
                .padding(18.dp)
        ) {
            Column {
                Text("NET SAVED", fontSize = 10.sp, fontWeight = FontWeight.SemiBold, color = GreenBright, letterSpacing = 0.8.sp, fontFamily = InterFontFamily)
                Text(
                    String.format(Locale.US, "LKR %.2f", totalBalance / 100.0),
                    fontSize = 28.sp, fontWeight = FontWeight.ExtraBold, color = White,
                    letterSpacing = (-1).sp, modifier = Modifier.padding(top = 4.dp, bottom = 14.dp),
                    fontFamily = InterFontFamily
                )
                HorizontalDivider(color = White.copy(alpha = 0.1f), thickness = 1.dp, modifier = Modifier.padding(bottom = 14.dp))
                Row(modifier = Modifier.fillMaxWidth()) {
                    Column(modifier = Modifier.weight(1f)) {
                        Text("Income", fontSize = 10.sp, fontWeight = FontWeight.Medium, color = GreenAccent, fontFamily = InterFontFamily, modifier = Modifier.padding(bottom = 3.dp))
                        Text(
                            String.format(Locale.US, "LKR %.2f", allTimeIncome / 100.0),
                            fontSize = 16.sp, fontWeight = FontWeight.Bold, color = White,
                            letterSpacing = (-0.5).sp, fontFamily = InterFontFamily
                        )
                    }
                    Box(modifier = Modifier.width(1.dp).height(40.dp).align(Alignment.CenterVertically).background(White.copy(alpha = 0.1f)))
                    Column(modifier = Modifier.weight(1f).padding(start = 16.dp)) {
                        Text("Expenses", fontSize = 10.sp, fontWeight = FontWeight.Medium, color = Color(0xFFFF8A80), fontFamily = InterFontFamily, modifier = Modifier.padding(bottom = 3.dp))
                        Text(
                            String.format(Locale.US, "LKR %.2f", allTimeExpenses / 100.0),
                            fontSize = 16.sp, fontWeight = FontWeight.Bold, color = White,
                            letterSpacing = (-0.5).sp, fontFamily = InterFontFamily
                        )
                    }
                }
            }
        }
    }
}

@Composable
private fun CircularProgressIndicator(
    percentage: Int,
    label: String,
    modifier: Modifier = Modifier,
    color: Color = GreenDeep
) {
    val cs = MaterialTheme.colorScheme

    Box(
        modifier = modifier
            .background(cs.surface, RoundedCornerShape(16.dp))
            .border(1.dp, cs.outline, RoundedCornerShape(16.dp))
            .padding(16.dp),
        contentAlignment = Alignment.Center
    ) {
        Canvas(modifier = Modifier.size(80.dp)) {
            val stroke = 4.dp.toPx()
            val inset = stroke / 2f
            val arcSize = androidx.compose.ui.geometry.Size(
                size.width - stroke,
                size.height - stroke
            )
            val topLeft = androidx.compose.ui.geometry.Offset(inset, inset)

            // Background track
            drawArc(
                color = cs.outlineVariant,
                startAngle = -90f,
                sweepAngle = 360f,
                useCenter = false,
                topLeft = topLeft,
                size = arcSize,
                style = Stroke(width = stroke, cap = StrokeCap.Round)
            )

            // Progress arc
            val sweepAngle = (percentage / 100f) * 360f
            drawArc(
                color = color,
                startAngle = -90f,
                sweepAngle = sweepAngle,
                useCenter = false,
                topLeft = topLeft,
                size = arcSize,
                style = Stroke(width = stroke, cap = StrokeCap.Round)
            )
        }

        Column(
            horizontalAlignment = Alignment.CenterHorizontally,
            modifier = Modifier.align(Alignment.Center)
        ) {
            Text(
                "$percentage%",
                fontSize = 20.sp,
                fontWeight = FontWeight.Bold,
                color = color,
                fontFamily = InterFontFamily
            )
            Text(
                label,
                fontSize = 10.sp,
                fontWeight = FontWeight.Medium,
                color = cs.onSurfaceVariant,
                fontFamily = InterFontFamily
            )
        }
    }
}

package com.example.northstar.ui.navigation

import androidx.compose.foundation.background
import androidx.compose.foundation.clickable
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.shape.CircleShape
import androidx.compose.foundation.shape.RoundedCornerShape
